// Format weekly readiness summary for notification
const digest = $input.item.json.digest || {};
const funnel = digest.funnel || {};
const readiness = digest.readiness || {};
const ingestion = digest.ingestion || {};

const lines = [
  `📊 Weekly Job Search OS Summary — ${new Date().toLocaleDateString()}`,
  '',
  '🎯 Readiness:',
  `  Ready to apply: ${readiness.readyToApplyCount || 0}`,
  `  High readiness (85%+): ${readiness.highReadinessCount || 0}`,
  `  Blocked (no URL): ${readiness.blockedByMissingUrlCount || 0}`,
  `  Follow-up due: ${readiness.appliedFollowUpDueCount || 0}`,
  '',
  '📦 Pipeline:',
  `  Discovered: ${funnel.discovered || 0}`,
  `  Approved: ${funnel.approved || 0}`,
  `  Applied: ${funnel.applied || 0}`,
  `  Interviewing: ${funnel.interviewing || 0}`,
  '',
  '📡 Ingestion (this week):',
  `  Runs: ${ingestion.runsTotal || 0}`,
  `  New jobs: ${ingestion.newJobsIngested || 0}`,
  `  Failures: ${ingestion.failures || 0}`,
];
return [{ json: { message: lines.join('\n'), digest } }];
